use aiken/collection/list
use aiken/fuzz
use cardano/assets.{lovelace_of}
use cardano/transaction.{Output, OutputReference, Transaction}
pub type CdpDatum {
  owner:               ByteArray,
  collateral_lovelace: Int,
  debt_lovelace:       Int,
  liquidation_ratio:   Int,
}

pub type CdpRedeemer {
  Repay
  Liquidate
}

/// True when the position is undercollateralized (eligible for liquidation)
fn is_undercollateralized(
  collateral: Int,
  debt:       Int,
  ratio:      Int,
) -> Bool {
  debt > 0 && collateral * 100 < debt * ratio
}

/// Liquidator must send at least debt_lovelace to the owner
fn liquidator_pays_debt(
  outputs:        List<Output>,
  owner_addr:     Output,
  debt_lovelace:  Int,
) -> Bool {
  let paid =
    list.foldl(
      outputs,
      0,
      fn(o, acc) {
        if o.address == owner_addr.address {
          acc + lovelace_of(o.value)
        } else {
          acc
        }
      },
    )
  paid >= debt_lovelace
}

validator cdp_liquidation {
  spend(
    datum: Option<CdpDatum>,
    redeemer: CdpRedeemer,
    _own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    expect Some(d) = datum
    when redeemer is {
      Repay ->
        // Owner repays: they must sign
        list.has(self.extra_signatories, d.owner)
      Liquidate ->
        // Anyone can liquidate when undercollateralized
        is_undercollateralized(
          d.collateral_lovelace,
          d.debt_lovelace,
          d.liquidation_ratio,
        )
    }
  }
}

// ── Property tests ──────────────────────────────────────────────────────────

test prop_undercollateralized_below_ratio(debt via fuzz.int_at_least(1)) {
  // collateral = debt * 119/100 < debt * 120/100 → undercollateralized at ratio 120
  is_undercollateralized(debt * 119, debt * 100, 120)
}

test prop_not_undercollateralized_above_ratio(debt via fuzz.int_at_least(1)) {
  !is_undercollateralized(debt * 150, debt * 100, 120)
}

test prop_undercollateralized_always_requires_debt(
  vals via fuzz.both(fuzz.int_at_least(0), fuzz.int_at_least(1)),
) {
  let (collateral, ratio) = vals
  !is_undercollateralized(collateral, 0, ratio)
}

test prop_undercollateralized_inverse_of_overcollateralized(
  vals via fuzz.both(fuzz.int_at_least(1), fuzz.int_at_least(1)),
) {
  let (collateral, debt) = vals
  let ratio = 150
  let under = is_undercollateralized(collateral, debt, ratio)
  let over  = collateral * 100 >= debt * ratio
  // They cannot both be true simultaneously
  !(under && over)
}

// ── Negative / fail tests ────────────────────────────────────────────────────

/// A well-collateralized position (collateral * 100 >= debt * ratio) must NOT
/// be flagged as undercollateralized.
test prop_overcollateralized_not_flagged(
  debt via fuzz.int_between(1, 1000),
) fail {
  // collateral = debt * 200, ratio = 150 → 200*100=20000 >= debt*150 always
  expect is_undercollateralized(debt * 200, debt, 150)
}

/// Zero debt must never be undercollateralized, regardless of collateral/ratio.
test prop_zero_debt_never_undercollateralized(
  vals via fuzz.both(fuzz.int_between(0, 1_000_000), fuzz.int_between(1, 300)),
) fail {
  let (collateral, ratio) = vals
  expect is_undercollateralized(collateral, 0, ratio)
}

/// liquidator_pays_debt with an empty output list and a positive debt
/// must always return False (no lovelace was paid).
test prop_no_outputs_fails_debt_payment(
  debt via fuzz.int_at_least(1),
) fail {
  // Build a dummy owner Output with an empty value just to satisfy the type.
  // The output list is empty so paid=0 < debt.
  let dummy_addr =
    cardano/address.from_verification_key(#"00000000000000000000000000000000000000000000000000000000")
  let dummy_output =
    Output {
      address: dummy_addr,
      value: cardano/assets.zero,
      datum: cardano/transaction.NoDatum,
      reference_script: None,
    }
  expect liquidator_pays_debt([], dummy_output, debt)
}

/// A position with very high collateral relative to debt and ratio=100 is
/// always healthy; flagging it as undercollateralized must fail.
test prop_full_ratio_overcollateralized_rejected() fail {
  // collateral=200, debt=1, ratio=100 → 200*100=20000 >= 1*100=100 → healthy
  expect is_undercollateralized(200, 1, 100)
}

use aiken/collection/list
use aiken/fuzz
use cardano/assets.{lovelace_of}
use cardano/transaction.{Output, OutputReference, Transaction}
pub type CdpDatum {
  owner:             ByteArray,
  collateral:        Int,
  debt:              Int,
  liquidation_ratio: Int,
  bonus_percent:     Int,
}

pub type CdpRedeemer {
  Repay
  Liquidate
}

fn is_undercollateralized(collateral: Int, debt: Int, ratio: Int) -> Bool {
  debt > 0 && collateral * 100 < debt * ratio
}

/// Liquidator pays discounted debt: debt * (100 - bonus_percent) / 100
fn discounted_debt(debt: Int, bonus_percent: Int) -> Int {
  debt * (100 - bonus_percent) / 100
}

fn liquidator_pays_discounted(
  outputs:       List<Output>,
  owner_addr:    Output,
  debt:          Int,
  bonus_percent: Int,
) -> Bool {
  let required = discounted_debt(debt, bonus_percent)
  let paid =
    list.foldl(
      outputs,
      0,
      fn(o, acc) {
        if o.address == owner_addr.address {
          acc + lovelace_of(o.value)
        } else {
          acc
        }
      },
    )
  paid >= required
}

validator cdp_liquidation_bonus {
  spend(
    datum: Option<CdpDatum>,
    redeemer: CdpRedeemer,
    _own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    expect Some(d) = datum
    when redeemer is {
      Repay -> list.has(self.extra_signatories, d.owner)
      Liquidate ->
        is_undercollateralized(d.collateral, d.debt, d.liquidation_ratio)
    }
  }
}

// ── Property tests ──────────────────────────────────────────────────────────

test prop_discounted_debt_zero_bonus(debt via fuzz.int_at_least(1)) {
  discounted_debt(debt, 0) == debt
}

test prop_discounted_debt_less_than_full(
  vals via fuzz.both(fuzz.int_at_least(100), fuzz.int_between(1, 50)),
) {
  let (debt, bonus) = vals
  discounted_debt(debt, bonus) < debt
}

test prop_discounted_debt_non_negative(
  vals via fuzz.both(fuzz.int_at_least(1), fuzz.int_between(0, 99)),
) {
  let (debt, bonus) = vals
  discounted_debt(debt, bonus) >= 0
}

test prop_undercollateralized_below_ratio(debt via fuzz.int_at_least(1)) {
  is_undercollateralized(debt * 119, debt * 100, 120)
}

// ── Negative / fail tests ────────────────────────────────────────────────────

// A position with zero debt is never undercollateralized regardless of collateral.
test prop_zero_debt_never_undercollateralized(
  vals via fuzz.both(fuzz.int_at_least(0), fuzz.int_between(1, 500)),
) fail {
  let (collateral, ratio) = vals
  expect is_undercollateralized(collateral, 0, ratio)
}

// A well-collateralized position (collateral * 100 >= debt * ratio) must not
// be flagged as undercollateralized.
// We pick collateral = debt * ratio so collateral * 100 == debt * ratio * 100 >= debt * ratio.
test prop_fully_collateralized_not_undercollateralized(
  vals via fuzz.both(fuzz.int_between(1, 100), fuzz.int_between(1, 200)),
) fail {
  let (debt, ratio) = vals
  // collateral * 100 = debt * ratio * 100 >= debt * ratio  → not under
  expect is_undercollateralized(debt * ratio, debt, ratio)
}

// liquidator_pays_discounted must reject when no outputs are provided,
// because paid=0 < required for any positive debt and bonus < 100.
test prop_no_outputs_fails_liquidator_pays(
  vals via fuzz.both(fuzz.int_between(1, 10000), fuzz.int_between(0, 99)),
) fail {
  let (debt, bonus) = vals
  // We need a dummy owner_addr Output; build the simplest possible one.
  // With an empty outputs list, paid=0 but required=discounted_debt(debt,bonus)>=1.
  // Use a placeholder value: lovelace_of([]) = 0.
  let dummy_output =
    Output {
      address: cardano/address.from_verification_key(#"deadbeef"),
      value: cardano/assets.zero,
      datum: cardano/transaction.NoDatum,
      reference_script: None,
    }
  expect liquidator_pays_discounted([], dummy_output, debt, bonus)
}

// is_undercollateralized must return False when collateral is large enough
// that collateral * 100 >= debt * ratio (over-collateralized case).
// collateral = debt * ratio + 1 ensures collateral * 100 >> debt * ratio.
test prop_overcollateralized_not_undercollateralized(
  vals via fuzz.both(fuzz.int_between(1, 50), fuzz.int_between(100, 200)),
) fail {
  let (debt, ratio) = vals
  // collateral * 100 = (debt * ratio + 1) * 100 > debt * ratio
  expect is_undercollateralized(debt * ratio + 1, debt, ratio)
}

use aiken/collection/list
use aiken/fuzz
use cardano/assets.{lovelace_of}
use cardano/transaction.{Output, OutputReference, Transaction}
pub type CdpDatum {
  owner:             ByteArray,
  collateral:        Int,
  debt:              Int,
  liquidation_ratio: Int,
  min_collateral:    Int,
}

pub type CdpRedeemer {
  Repay
  Liquidate
}

fn is_undercollateralized(collateral: Int, debt: Int, ratio: Int) -> Bool {
  debt > 0 && collateral * 100 < debt * ratio
}

/// Position must have at least min_collateral to be liquidatable (dust guard)
fn is_liquidatable(
  collateral:     Int,
  debt:           Int,
  ratio:          Int,
  min_collateral: Int,
) -> Bool {
  collateral >= min_collateral && is_undercollateralized(collateral, debt, ratio)
}

fn liquidator_pays_debt(
  outputs:       List<Output>,
  owner_addr:    Output,
  debt_lovelace: Int,
) -> Bool {
  let paid =
    list.foldl(
      outputs,
      0,
      fn(o, acc) {
        if o.address == owner_addr.address {
          acc + lovelace_of(o.value)
        } else {
          acc
        }
      },
    )
  paid >= debt_lovelace
}

validator cdp_dust_guard {
  spend(
    datum: Option<CdpDatum>,
    redeemer: CdpRedeemer,
    _own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    expect Some(d) = datum
    when redeemer is {
      Repay -> list.has(self.extra_signatories, d.owner)
      Liquidate ->
        is_liquidatable(
          d.collateral,
          d.debt,
          d.liquidation_ratio,
          d.min_collateral,
        )
    }
  }
}

// ── Property tests ──────────────────────────────────────────────────────────

test prop_dust_guard_undercollateralized_above_min(debt via fuzz.int_at_least(1)) {
  let collateral = debt * 119
  is_liquidatable(collateral, debt * 100, 120, 1)
}

test prop_dust_guard_below_min_not_liquidatable(debt via fuzz.int_at_least(1)) {
  let collateral = debt * 119
  !is_liquidatable(collateral, debt * 100, 120, collateral + 1)
}

test prop_dust_guard_overcollateralized_not_liquidatable(debt via fuzz.int_at_least(1)) {
  !is_liquidatable(debt * 150, debt * 100, 120, 1)
}

test prop_undercollateralized_inverse(
  vals via fuzz.both(fuzz.int_at_least(1), fuzz.int_at_least(1)),
) {
  let (collateral, debt) = vals
  let ratio = 150
  !(is_undercollateralized(collateral, debt, ratio) && collateral * 100 >= debt * ratio)
}

// ── Negative (fail) tests ────────────────────────────────────────────────────

/// A well-collateralized position (collateral*100 >= debt*ratio) must NOT be
/// flagged as undercollateralized.
test prop_overcollateralized_not_undercollateralized(
  debt via fuzz.int_between(1, 1000),
) fail {
  // collateral = debt * ratio, so collateral*100 == debt*100*ratio >= debt*ratio
  // is_undercollateralized should return False
  let ratio = 150
  let collateral = debt * ratio
  expect is_undercollateralized(collateral, debt, ratio)
}

/// Zero debt means no position can ever be undercollateralized regardless of
/// collateral and ratio values.
test prop_zero_debt_not_undercollateralized(
  vals via fuzz.both(fuzz.int_between(1, 10000), fuzz.int_between(1, 500)),
) fail {
  let (collateral, ratio) = vals
  // debt = 0 → is_undercollateralized always False
  expect is_undercollateralized(collateral, 0, ratio)
}

/// A position that is below the dust-guard threshold (collateral < min_collateral)
/// must NOT be liquidatable even when genuinely undercollateralized.
test prop_below_min_collateral_not_liquidatable(
  debt via fuzz.int_between(1, 1000),
) fail {
  // collateral = 1, min_collateral = 2  →  collateral < min_collateral
  // ratio = 150, debt >= 1  →  1*100=100 < debt*150 for debt>=1, so undercollateralized
  // But is_liquidatable should still return False due to dust guard
  expect is_liquidatable(1, debt, 150, 2)
}

/// liquidator_pays_debt must return False when the outputs list is empty —
/// no lovelace can have been paid to the owner.
test prop_no_outputs_fails_debt_payment(
  debt_lovelace via fuzz.int_at_least(1),
) fail {
  // With an empty output list the fold yields 0, which is < any positive debt
  // We need a dummy owner_addr — build the simplest possible Output inline.
  // Since we can't easily construct an Output here without a full address,
  // we rely on the fact that paid=0 < debt_lovelace for all debt_lovelace >= 1.
  expect liquidator_pays_debt([], Output { address: cardano/address.from_verification_key(#""), value: cardano/assets.zero, datum: cardano/transaction.NoDatum, reference_script: None }, debt_lovelace)
}

use aiken/collection/list
use aiken/crypto.{VerificationKeyHash}
use aiken/fuzz
use cardano/address
use cardano/assets.{PolicyId, quantity_of}
use cardano/fuzz as cfuzz
use cardano/transaction.{InlineDatum, Output, OutputReference, Transaction}
pub type State {
  Idle
  Active
  Locked
  Closing
}

pub type StateRedeemer {
  Advance
  Reset
  Terminate
}

pub type MachineDatum {
  state:        State,
  admin:        VerificationKeyHash,
  beacon_policy: PolicyId,
  beacon_name:  ByteArray,
}

/// Valid transitions: Idle→Active, Active→Locked, Locked→Closing
fn valid_transition(from: State, to: State, redeemer: StateRedeemer) -> Bool {
  when redeemer is {
    Advance ->
      when from is {
        Idle    -> to == Active
        Active  -> to == Locked
        Locked  -> to == Closing
        Closing -> False
      }
    Reset     -> to == Idle
    Terminate -> to == Closing
  }
}

/// The beacon NFT must be present in the continuing output
fn beacon_preserved(
  outputs:      List<Output>,
  own_addr:     address.Address,
  beacon_policy: PolicyId,
  beacon_name:  ByteArray,
) -> Bool {
  list.any(
    outputs,
    fn(o) {
      o.address == own_addr
        && quantity_of(o.value, beacon_policy, beacon_name) == 1
    },
  )
}

fn state_from_output(output: Output) -> Option<MachineDatum> {
  when output.datum is {
    InlineDatum(raw) -> {
      expect d: MachineDatum = raw
      Some(d)
    }
    _ -> None
  }
}

validator beacon_state_machine {
  spend(
    datum: Option<MachineDatum>,
    redeemer: StateRedeemer,
    own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    expect Some(d) = datum
    // Find own input to get address
    expect Some(own_input) =
      list.find(self.inputs, fn(i) { i.output_reference == own_ref })
    let own_addr = own_input.output.address
    // Find continuing output with new datum
    expect Some(next_output) =
      list.find(self.outputs, fn(o) { o.address == own_addr })
    expect Some(next_d) = state_from_output(next_output)
    // Validate
    valid_transition(d.state, next_d.state, redeemer)
      && beacon_preserved(self.outputs, own_addr, d.beacon_policy, d.beacon_name)
      && (
        when redeemer is {
          Advance -> True
          Reset   -> list.has(self.extra_signatories, d.admin)
          Terminate -> list.has(self.extra_signatories, d.admin)
        }
      )
  }
}

// ── Property tests ──────────────────────────────────────────────────────────

test prop_valid_transition_advance_idle() {
  valid_transition(Idle, Active, Advance)
}

test prop_valid_transition_advance_active() {
  valid_transition(Active, Locked, Advance)
}

test prop_valid_transition_advance_locked() {
  valid_transition(Locked, Closing, Advance)
}

test prop_valid_transition_closing_advance_fails() {
  !valid_transition(Closing, Idle, Advance)
}

test prop_valid_transition_reset_always_to_idle() {
  valid_transition(Active, Idle, Reset)
    && valid_transition(Locked, Idle, Reset)
    && valid_transition(Closing, Idle, Reset)
}

test prop_valid_transition_wrong_target_fails() {
  !valid_transition(Idle, Locked, Advance)
}

// ── Negative (fail) tests ────────────────────────────────────────────────────

/// Closing state can never advance to any state
test prop_closing_advance_always_rejected() fail {
  expect valid_transition(Closing, Closing, Advance)
}

/// Idle→Locked is not a valid Advance transition (must go Idle→Active)
test prop_idle_to_locked_advance_rejected() fail {
  expect valid_transition(Idle, Locked, Advance)
}

/// Reset must always produce Idle; any non-Idle target must be rejected
test prop_reset_to_active_rejected() fail {
  expect valid_transition(Active, Active, Reset)
}

/// beacon_preserved returns False when the outputs list is empty
test prop_beacon_not_preserved_empty_outputs(
  own_addr via cfuzz.address(),
  policy via cfuzz.policy_id(),
  name via cfuzz.asset_name(),
) fail {
  expect beacon_preserved([], own_addr, policy, name)
}

use aiken/collection/list
use aiken/crypto.{VerificationKeyHash}
use aiken/fuzz
use cardano/address
use cardano/assets.{PolicyId, quantity_of}
use cardano/fuzz as cfuzz
use cardano/transaction.{InlineDatum, Output, OutputReference, Transaction}
pub type ApprovalState {
  Draft
  Review
  Approved
  Rejected
}

pub type ApprovalRedeemer {
  Submit
  Approve
  Reject
  Revise
}

pub type ApprovalDatum {
  state:         ApprovalState,
  admin:         VerificationKeyHash,
  beacon_policy: PolicyId,
  beacon_name:   ByteArray,
}

fn valid_approval_transition(
  from:     ApprovalState,
  to:       ApprovalState,
  redeemer: ApprovalRedeemer,
) -> Bool {
  when redeemer is {
    Submit  -> from == Draft && to == Review
    Approve -> from == Review && to == Approved
    Reject  -> from == Review && to == Rejected
    Revise  -> from == Rejected && to == Draft
  }
}

fn beacon_preserved(
  outputs:       List<Output>,
  own_addr:      address.Address,
  beacon_policy: PolicyId,
  beacon_name:   ByteArray,
) -> Bool {
  list.any(
    outputs,
    fn(o) {
      o.address == own_addr
        && quantity_of(o.value, beacon_policy, beacon_name) == 1
    },
  )
}

fn datum_from_output(output: Output) -> Option<ApprovalDatum> {
  when output.datum is {
    InlineDatum(raw) -> {
      expect d: ApprovalDatum = raw
      Some(d)
    }
    _ -> None
  }
}

validator beacon_approval {
  spend(
    datum: Option<ApprovalDatum>,
    redeemer: ApprovalRedeemer,
    own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    expect Some(d) = datum
    expect Some(own_input) =
      list.find(self.inputs, fn(i) { i.output_reference == own_ref })
    let own_addr = own_input.output.address
    expect Some(next_output) =
      list.find(self.outputs, fn(o) { o.address == own_addr })
    expect Some(next_d) = datum_from_output(next_output)
    valid_approval_transition(d.state, next_d.state, redeemer)
      && beacon_preserved(self.outputs, own_addr, d.beacon_policy, d.beacon_name)
      && list.has(self.extra_signatories, d.admin)
  }
}

// ── Property tests ──────────────────────────────────────────────────────────

test prop_submit_draft_to_review() {
  valid_approval_transition(Draft, Review, Submit)
}

test prop_approve_review_to_approved() {
  valid_approval_transition(Review, Approved, Approve)
}

test prop_reject_review_to_rejected() {
  valid_approval_transition(Review, Rejected, Reject)
}

test prop_revise_rejected_to_draft() {
  valid_approval_transition(Rejected, Draft, Revise)
}

// ── Negative / fail tests ────────────────────────────────────────────────────

// Submit requires Draft→Review; Approved is never a valid "from" state for Submit
test prop_submit_from_approved_rejected() fail {
  expect valid_approval_transition(Approved, Review, Submit)
}

// Approve requires Review→Approved; starting from Draft must always fail
test prop_approve_from_draft_fails() fail {
  expect valid_approval_transition(Draft, Approved, Approve)
}

// Reject requires Review→Rejected; starting from Draft must always fail
test prop_reject_from_draft_fails() fail {
  expect valid_approval_transition(Draft, Rejected, Reject)
}

// beacon_preserved with an empty output list must always return False
test prop_beacon_not_preserved_in_empty_outputs(
  policy via cfuzz.policy_id(),
  name via cfuzz.asset_name(),
  addr via cfuzz.address(),
) fail {
  expect beacon_preserved([], addr, policy, name)
}

use aiken/collection/list
use aiken/crypto.{VerificationKeyHash}
use aiken/fuzz
use cardano/address
use cardano/assets.{PolicyId, quantity_of}
use cardano/fuzz as cfuzz
use cardano/transaction.{InlineDatum, Output, OutputReference, Transaction}
pub type Step {
  Step0
  Step1
  Step2
  Step3
}

pub type StepRedeemer {
  Next
  Rollback
  Abort
}

pub type StepDatum {
  step:          Step,
  admin:         VerificationKeyHash,
  beacon_policy: PolicyId,
  beacon_name:   ByteArray,
}

/// Next advances, Rollback goes one step back, Abort resets to Step0
fn valid_step_transition(from: Step, to: Step, redeemer: StepRedeemer) -> Bool {
  when redeemer is {
    Next ->
      when from is {
        Step0 -> to == Step1
        Step1 -> to == Step2
        Step2 -> to == Step3
        Step3 -> False
      }
    Rollback ->
      when from is {
        Step0 -> False
        Step1 -> to == Step0
        Step2 -> to == Step1
        Step3 -> to == Step2
      }
    Abort -> to == Step0
  }
}

fn beacon_preserved(
  outputs:       List<Output>,
  own_addr:      address.Address,
  beacon_policy: PolicyId,
  beacon_name:   ByteArray,
) -> Bool {
  list.any(
    outputs,
    fn(o) {
      o.address == own_addr
        && quantity_of(o.value, beacon_policy, beacon_name) == 1
    },
  )
}

fn datum_from_output(output: Output) -> Option<StepDatum> {
  when output.datum is {
    InlineDatum(raw) -> {
      expect d: StepDatum = raw
      Some(d)
    }
    _ -> None
  }
}

validator beacon_rollback {
  spend(
    datum: Option<StepDatum>,
    redeemer: StepRedeemer,
    own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    expect Some(d) = datum
    expect Some(own_input) =
      list.find(self.inputs, fn(i) { i.output_reference == own_ref })
    let own_addr = own_input.output.address
    expect Some(next_output) =
      list.find(self.outputs, fn(o) { o.address == own_addr })
    expect Some(next_d) = datum_from_output(next_output)
    valid_step_transition(d.step, next_d.step, redeemer)
      && beacon_preserved(self.outputs, own_addr, d.beacon_policy, d.beacon_name)
  }
}

// ── Property tests ──────────────────────────────────────────────────────────

