/// fee_bps >= 10000 means fee >= gross, so fee_valid must return False
test prop_fee_bps_at_least_10000_invalid(
  vals via fuzz.both(
    fuzz.int_between(1, 1000),
    fuzz.int_between(10000, 20000),
  ),
) fail {
  let (qty, fee_bps) = vals
  // gross = qty * 1, fee = qty * 1 * fee_bps / 10000 >= qty = gross
  expect fee_valid(qty, 1, fee_bps)
}

/// Zero fill_qty makes gross = 0, so fee_valid returns False (fee < gross fails: 0 < 0 is False)
test prop_zero_qty_fee_invalid(
  price via fuzz.int_between(1, 1000),
) fail {
  expect fee_valid(0, price, 30)
}

/// Zero price makes gross = 0, so fee_valid returns False (fee < gross fails: 0 < 0 is False)
test prop_zero_price_fee_invalid(
  qty via fuzz.int_between(1, 1000),
) fail {
  expect fee_valid(qty, 0, 30)
}

/// Negative fill_qty makes gross negative; fee_valid returns False
/// because fee = negative * price * fee_bps / 10000 is negative, so fee >= 0 fails
test prop_negative_qty_fee_invalid(
  vals via fuzz.both(
    fuzz.int_between(-1000, -1),
    fuzz.int_between(1, 1000),
  ),
) fail {
  let (neg_qty, price) = vals
  expect fee_valid(neg_qty, price, 30)
}
